    61→// GenerateLabelPDF generates an A4 label PDF and returns the raw bytes.
    62→func (g *Generator) GenerateLabelPDF(
    63→	job entity.PrintJob,
    64→	contacts []entity.Contact,
    65→	sender *entity.Sender,
    66→) ([]byte, error) {
    67→	pdf := gofpdf.New("P", "mm", "A4", "")
    68→	pdf.SetMargins(0, 0, 0)
    69→	pdf.SetAutoPageBreak(false, 0)
    70→	pdf.SetCompression(true)
    71→
    72→	// Register Japanese font if available.
    73→	// Use AddUTF8FontFromBytes to avoid gofpdf's internal filepath.Join
    74→	// mangling absolute paths when its fontpath is non-empty.
    75→	const fontName = "jfont"
    76→	hasJFont := false
    77→	if g.fontPath != "" {
    78→		if fontBytes, err := os.ReadFile(g.fontPath); err == nil {
    79→			pdf.AddUTF8FontFromBytes(fontName, "", fontBytes)
    80→			if pdf.Error() == nil {
    81→				hasJFont = true
    82→			}
    83→		}
    84→	}
    85→
    86→	setFont := func(size float64) {
    87→		if hasJFont {
    88→			pdf.SetFont(fontName, "", size)
    89→		} else {
    90→			pdf.SetFont("Courier", "", size)
    91→		}
    92→	}
    93→
    94→	layout := job.LabelLayout
    95→	tmpl := job.Template
    96→
    97→	labelsPerPage := layout.Columns * layout.Rows
    98→	if labelsPerPage == 0 {
    99→		return nil, fmt.Errorf("invalid label layout: columns=%d rows=%d", layout.Columns, layout.Rows)
   100→	}
   101→
   102→	// Pre-generate QR PNG bytes once (reused for every label).
   103→	var qrPNG []byte
   104→	if job.QRConfig != nil && job.QRConfig.Enabled && job.QRConfig.Content != "" {
   105→		sizePx := job.QRConfig.Size
   106→		if sizePx <= 0 {
   107→			sizePx = 128
   108→		}
   109→		var err error
   110→		qrPNG, err = qrcode.Encode(job.QRConfig.Content, qrcode.Medium, sizePx)
   111→		if err != nil {
   112→			// QR generation failure is non-fatal.
   113→			qrPNG = nil
   114→		}
   115→	}
   116→
   117→	for i, contact := range contacts {
   118→		if i%labelsPerPage == 0 {
   119→			pdf.AddPage()
   120→		}
   121→
   122→		pageIdx := i % labelsPerPage
   123→		col := pageIdx % layout.Columns
   124→		row := pageIdx / layout.Columns
   125→
   126→		originX := layout.MarginLeft + float64(col)*(layout.LabelWidth+layout.GapX) + layout.OffsetX
   127→		originY := layout.MarginTop + float64(row)*(layout.LabelHeight+layout.GapY) + layout.OffsetY
   128→
   129→		// Watermark background.
   130→		if job.Watermark != nil && job.Watermark.FilePath != "" {
   131→			if _, err := os.Stat(job.Watermark.FilePath); err == nil {
   132→				imgType := imageType(job.Watermark.FilePath)
   133→				opts := gofpdf.ImageOptions{ImageType: imgType}
   134→				pdf.ImageOptions(job.Watermark.FilePath, originX, originY, layout.LabelWidth, layout.LabelHeight, false, opts, 0, "")
   135→			}
   136→		}
   137→
   138→		// Label content.
   139→		drawLabel(pdf, setFont, &contact, sender, tmpl, originX, originY)
   140→
   141→		// QR code.
   142→		if qrPNG != nil {
   143→			drawQR(pdf, job.QRConfig, qrPNG, originX, originY, layout.LabelWidth, layout.LabelHeight, i)
   144→		}
   145→	}
   146→
   147→	var buf bytes.Buffer
   148→	if err := pdf.Output(&buf); err != nil {
   149→		return nil, fmt.Errorf("pdf output: %w", err)
   150→	}
   151→	return buf.Bytes(), nil
   152→}
   153→
   154→// drawQR places a pre-generated QR PNG at the configured position within the label.
   155→func drawQR(pdf *gofpdf.Fpdf, qr *entity.QRConfig, pngBytes []byte, originX, originY, labelW, labelH float64, idx int) {
   156→	// size in mm: qr.Size pixels * 0.264583 mm/px (96 dpi)
   157→	sizeMM := float64(qr.Size) * 0.264583
   158→	if sizeMM < 15 {
   159→		sizeMM = 15 // minimum readable QR size
   160→	}
   161→
   162→	var qrX, qrY float64
   163→	switch qr.Position {
   164→	case "top-left":
   165→		qrX = originX + 1
   166→		qrY = originY + 1
   167→	case "top-right":
   168→		qrX = originX + labelW - sizeMM - 1
   169→		qrY = originY + 1
   170→	case "bottom-left":
   171→		qrX = originX + 1
   172→		qrY = originY + labelH - sizeMM - 1
   173→	default: // "bottom-right"
   174→		qrX = originX + labelW - sizeMM - 1
   175→		qrY = originY + labelH - sizeMM - 1
   176→	}
   177→
   178→	// Register once with a fixed key; gofpdf caches it after first registration.
   179→	const imgKey = "qr_code"
   180→	if idx == 0 {
   181→		reader := bytes.NewReader(pngBytes)
   182→		pdf.RegisterImageOptionsReader(imgKey, gofpdf.ImageOptions{ImageType: "PNG"}, reader)
   183→	}
   184→	pdf.ImageOptions(imgKey, qrX, qrY, sizeMM, sizeMM, false, gofpdf.ImageOptions{ImageType: "PNG"}, 0, "")
   185→}
