   187→// drawLabel renders postal code, recipient and sender onto a single label cell.
   188→func drawLabel(
   189→	pdf *gofpdf.Fpdf,
   190→	setFont func(float64),
   191→	contact *entity.Contact,
   192→	sender *entity.Sender,
   193→	tmpl entity.Template,
   194→	ox, oy float64,
   195→) {
   196→	pdf.SetTextColor(0, 0, 0)
   197→
   198→	// Postal code digits.
   199→	if tmpl.PostalCode != nil && contact.PostalCode != "" {
   200→		setFont(tmpl.PostalCode.FontSize)
   201→		digits := strings.ReplaceAll(contact.PostalCode, "-", "")
   202→		spacing := tmpl.PostalCode.DigitSpacing
   203→		if spacing <= 0 {
   204→			spacing = 4
   205→		}
   206→		cellH := tmpl.PostalCode.FontSize * 0.4
   207→		for i, ch := range digits {
   208→			xPos := ox + tmpl.PostalCode.X + float64(i)*spacing
   209→			pdf.SetXY(xPos, oy+tmpl.PostalCode.Y)
   210→			pdf.CellFormat(spacing, cellH, string(ch), "", 0, "C", false, 0, "")
   211→		}
   212→	}
   213→
   214→	// Recipient name.
   215→	rec := tmpl.Recipient
   216→	honorific := contact.Honorific
   217→	if honorific == "" {
   218→		honorific = "様"
   219→	}
   220→
   221→	var nameLines []string
   222→	if contact.Company != "" {
   223→		nameLines = append(nameLines, contact.Company)
   224→		if contact.Department != "" {
   225→			nameLines = append(nameLines, contact.Department)
   226→		}
   227→	}
   228→	fullName := contact.FamilyName + contact.GivenName + " " + honorific
   229→	nameLines = append(nameLines, fullName)
   230→
   231→	addr := buildAddress(contact)
   232→
   233→	if tmpl.Orientation == "vertical" {
   234→		setFont(rec.NameFont)
   235→		xOff := ox + rec.NameX
   236→		for _, line := range nameLines {
   237→			drawVerticalText(pdf, line, xOff, oy+rec.NameY, rec.NameFont)
   238→			xOff -= rec.NameFont * 0.5 // next column to the left
   239→		}
   240→
   241→		setFont(rec.AddressFont)
   242→		drawVerticalText(pdf, addr, ox+rec.AddressX, oy+rec.AddressY, rec.AddressFont)
   243→	} else {
   244→		setFont(rec.NameFont)
   245→		lineH := rec.NameFont * 0.5
   246→		for i, line := range nameLines {
   247→			pdf.SetXY(ox+rec.NameX, oy+rec.NameY+float64(i)*lineH)
   248→			pdf.CellFormat(0, lineH, line, "", 0, "L", false, 0, "")
   249→		}
   250→
   251→		setFont(rec.AddressFont)
   252→		pdf.SetXY(ox+rec.AddressX, oy+rec.AddressY)
   253→		pdf.CellFormat(0, rec.AddressFont*0.5, addr, "", 0, "L", false, 0, "")
   254→	}
   255→
   256→	// Sender.
   257→	if sender != nil {
   258→		snd := tmpl.Sender
   259→		senderName := sender.FamilyName + sender.GivenName
   260→		if sender.Company != "" {
   261→			senderName = sender.Company + " " + senderName
   262→		}
   263→		senderAddr := buildSenderAddress(sender)
   264→
   265→		if tmpl.Orientation == "vertical" {
   266→			setFont(snd.NameFont)
   267→			drawVerticalText(pdf, senderName, ox+snd.NameX, oy+snd.NameY, snd.NameFont)
   268→			setFont(snd.AddressFont)
   269→			drawVerticalText(pdf, senderAddr, ox+snd.AddressX, oy+snd.AddressY, snd.AddressFont)
   270→		} else {
   271→			setFont(snd.NameFont)
   272→			pdf.SetXY(ox+snd.NameX, oy+snd.NameY)
   273→			pdf.CellFormat(0, snd.NameFont*0.5, senderName, "", 0, "L", false, 0, "")
   274→			setFont(snd.AddressFont)
   275→			pdf.SetXY(ox+snd.AddressX, oy+snd.AddressY)
   276→			pdf.CellFormat(0, snd.AddressFont*0.5, senderAddr, "", 0, "L", false, 0, "")
   277→		}
   278→	}
   279→}
   280→
   281→// drawVerticalText places each rune top-to-bottom in a single column.
   282→func drawVerticalText(pdf *gofpdf.Fpdf, text string, x, y, fontSize float64) {
   283→	charW := fontSize * 0.45
   284→	lineH := fontSize * 0.48
   285→	for i, ch := range text {
   286→		pdf.SetXY(x, y+float64(i)*lineH)
   287→		pdf.CellFormat(charW, lineH, string(ch), "", 0, "C", false, 0, "")
   288→	}
   289→}
