   173→	if fontOff+dirSize > len(ttcBytes) {
   174→		return nil
   175→	}
   176→
   177→	type tableInfo struct {
   178→		tag      [4]byte
   179→		checksum uint32
   180→		srcOff   uint32
   181→		length   uint32
   182→	}
   183→	tables := make([]tableInfo, numTables)
   184→	for i := 0; i < numTables; i++ {
   185→		b := fontOff + 12 + i*16
   186→		copy(tables[i].tag[:], ttcBytes[b:b+4])
   187→		tables[i].checksum = binary.BigEndian.Uint32(ttcBytes[b+4 : b+8])
   188→		tables[i].srcOff = binary.BigEndian.Uint32(ttcBytes[b+8 : b+12])
   189→		tables[i].length = binary.BigEndian.Uint32(ttcBytes[b+12 : b+16])
   190→		if int(tables[i].srcOff)+int(tables[i].length) > len(ttcBytes) {
   191→			return nil
   192→		}
   193→	}
   194→
   195→	newOffsets := make([]uint32, numTables)
   196→	cur := uint32(dirSize)
   197→	for i, t := range tables {
   198→		newOffsets[i] = cur
   199→		cur += (t.length + 3) &^ 3
   200→	}
   201→
   202→	result := make([]byte, int(cur))
   203→	copy(result[0:4], ttcBytes[fontOff:fontOff+4]) // sfVersion
   204→	binary.BigEndian.PutUint16(result[4:6], uint16(numTables))
   205→	es := uint16(0)
   206→	for n := numTables; n > 1; n >>= 1 {
   207→		es++
   208→	}
   209→	sr := uint16(1<<es) * 16
   210→	binary.BigEndian.PutUint16(result[6:8], sr)
   211→	binary.BigEndian.PutUint16(result[8:10], es)
   212→	binary.BigEndian.PutUint16(result[10:12], uint16(numTables)*16-sr)
   213→
   214→	for i, t := range tables {
   215→		b := 12 + i*16
   216→		copy(result[b:b+4], t.tag[:])
   217→		binary.BigEndian.PutUint32(result[b+4:b+8], t.checksum)
   218→		binary.BigEndian.PutUint32(result[b+8:b+12], newOffsets[i])
   219→		binary.BigEndian.PutUint32(result[b+12:b+16], t.length)
   220→		copy(result[newOffsets[i]:newOffsets[i]+t.length], ttcBytes[t.srcOff:t.srcOff+t.length])
   221→	}
   222→	return result
   223→}
   224→
   225→// japaneseCoverageChars are traditional CJK characters that are present in
   226→// Traditional Chinese / Japanese fonts but absent from Simplified Chinese fonts
   227→// (whose simplified equivalents use different Unicode codepoints).
   228→var japaneseCoverageChars = []rune{
   229→	'東', '達', '橋', '様', '際', '応', '辺', '澤', '廣', '邊',
   230→}
   231→
   232→// japaneseCmapScore returns the number of japaneseCoverageChars mapped in the
   233→// font's Unicode BMP cmap (Format 4). A higher score indicates better Japanese
   234→// character coverage.
   235→func japaneseCmapScore(ttfBytes []byte) int {
   236→	if len(ttfBytes) < 12 {
   237→		return 0
   238→	}
   239→	numTables := int(binary.BigEndian.Uint16(ttfBytes[4:6]))
   240→
   241→	var cmapOff, cmapLen uint32
   242→	for i := 0; i < numTables; i++ {
   243→		b := 12 + i*16
   244→		if b+16 > len(ttfBytes) {
   245→			break
   246→		}
   247→		if string(ttfBytes[b:b+4]) == "cmap" {
   248→			cmapOff = binary.BigEndian.Uint32(ttfBytes[b+8 : b+12])
   249→			cmapLen = binary.BigEndian.Uint32(ttfBytes[b+12 : b+16])
   250→			break
   251→		}
   252→	}
   253→	if cmapOff == 0 || int(cmapOff+cmapLen) > len(ttfBytes) {
   254→		return 0
   255→	}
   256→	cmap := ttfBytes[cmapOff : cmapOff+cmapLen]
   257→	if len(cmap) < 4 {
   258→		return 0
   259→	}
   260→
   261→	// Locate the Unicode BMP subtable (prefer platform 3 encoding 1).
   262→	numSubtables := int(binary.BigEndian.Uint16(cmap[2:4]))
   263→	var subOff uint32
   264→	for i := 0; i < numSubtables; i++ {
   265→		base := 4 + i*8
   266→		if base+8 > len(cmap) {
   267→			break
   268→		}
   269→		platformID := binary.BigEndian.Uint16(cmap[base : base+2])
   270→		encodingID := binary.BigEndian.Uint16(cmap[base+2 : base+4])
   271→		off := binary.BigEndian.Uint32(cmap[base+4 : base+8])
   272→		if (platformID == 3 && encodingID == 1) || (platformID == 0 && encodingID >= 3) {
   273→			subOff = off
   274→			break
   275→		}
   276→	}
   277→	if subOff == 0 || int(subOff)+14 > len(cmap) {
   278→		return 0
   279→	}
   280→	sub := cmap[subOff:]
   281→	if len(sub) < 14 || binary.BigEndian.Uint16(sub[0:2]) != 4 {
   282→		return 0 // only Format 4 handled
   283→	}
   284→
   285→	segCount := int(binary.BigEndian.Uint16(sub[6:8])) / 2
   286→	endBase := 14
   287→	startBase := 14 + segCount*2 + 2
   288→	deltaBase := 14 + segCount*4 + 2
   289→	rangeBase := 14 + segCount*6 + 2
   290→	if rangeBase+segCount*2 > len(sub) {
   291→		return 0
   292→	}
   293→
   294→	count := 0
   295→	for _, ch := range japaneseCoverageChars {
   296→		cp := uint16(ch)
   297→		for s := 0; s < segCount; s++ {
   298→			end := binary.BigEndian.Uint16(sub[endBase+s*2 : endBase+s*2+2])
   299→			if cp > end {
   300→				continue // segment endCode < cp, try next
   301→			}
   302→			start := binary.BigEndian.Uint16(sub[startBase+s*2 : startBase+s*2+2])
   303→			if cp >= start {
   304→				rangeOff := binary.BigEndian.Uint16(sub[rangeBase+s*2 : rangeBase+s*2+2])
   305→				if rangeOff == 0 {
   306→					delta := int16(binary.BigEndian.Uint16(sub[deltaBase+s*2 : deltaBase+s*2+2]))
   307→					if (int(cp)+int(delta))&0xFFFF != 0 {
   308→						count++
   309→					}
   310→				} else {
   311→					count++ // glyphIdArray path — assume mapped
   312→				}
   313→			}
   314→			break // segments are sorted by endCode; no further match possible
   315→		}
   316→	}
   317→	return count
   318→}
   319→
   320→// GenerateLabelPDF generates an A4 label PDF and returns the raw bytes.
   321→func (g *Generator) GenerateLabelPDF(
   322→	job entity.PrintJob,
   323→	contacts []entity.Contact,
   324→	sender *entity.Sender,
   325→) ([]byte, error) {
   326→	pdf := gofpdf.New("P", "mm", "A4", "")
   327→	pdf.SetMargins(0, 0, 0)
   328→	pdf.SetAutoPageBreak(false, 0)
   329→	pdf.SetCompression(true)
   330→
   331→	// Register Japanese font if available.
   332→	// Use pre-validated fontBytes to avoid TTC/OTF files that register
   333→	// without error but fail at pdf.Output() with "undefined font".
   334→	const fontName = "jfont"
   335→	hasJFont := false
   336→	if g.fontBytes != nil {
   337→		pdf.AddUTF8FontFromBytes(fontName, "", g.fontBytes)
   338→		if pdf.Error() == nil {
   339→			hasJFont = true
   340→		}
   341→	}
   342→
   343→	setFont := func(size float64) {
   344→		if hasJFont {
   345→			pdf.SetFont(fontName, "", size)
   346→		} else {
   347→			pdf.SetFont("Courier", "", size)
   348→		}
   349→	}
   350→
   351→	layout := job.LabelLayout
   352→	tmpl := job.Template
   353→
   354→	labelsPerPage := layout.Columns * layout.Rows
   355→	if labelsPerPage == 0 {
   356→		return nil, fmt.Errorf("invalid label layout: columns=%d rows=%d", layout.Columns, layout.Rows)
   357→	}
   358→
   359→	// Pre-generate QR PNG bytes once (reused for every label).
   360→	var qrPNG []byte
   361→	if job.QRConfig != nil && job.QRConfig.Enabled && job.QRConfig.Content != "" {
   362→		sizePx := job.QRConfig.Size
   363→		if sizePx <= 0 {
   364→			sizePx = 128
   365→		}
   366→		var err error
   367→		qrPNG, err = qrcode.Encode(job.QRConfig.Content, qrcode.Medium, sizePx)
   368→		if err != nil {
   369→			// QR generation failure is non-fatal.
   370→			qrPNG = nil
   371→		}
   372→	}
   373→
   374→	for i, contact := range contacts {
   375→		if i%labelsPerPage == 0 {
   376→			pdf.AddPage()
   377→		}
   378→
   379→		pageIdx := i % labelsPerPage
   380→		col := pageIdx % layout.Columns
   381→		row := pageIdx / layout.Columns
   382→
   383→		originX := layout.MarginLeft + float64(col)*(layout.LabelWidth+layout.GapX) + layout.OffsetX
   384→		originY := layout.MarginTop + float64(row)*(layout.LabelHeight+layout.GapY) + layout.OffsetY
   385→
   386→		// Watermark background.
   387→		if job.Watermark != nil && job.Watermark.FilePath != "" {
   388→			if _, err := os.Stat(job.Watermark.FilePath); err == nil {
   389→				imgType := imageType(job.Watermark.FilePath)
   390→				opts := gofpdf.ImageOptions{ImageType: imgType}
   391→				pdf.ImageOptions(job.Watermark.FilePath, originX, originY, layout.LabelWidth, layout.LabelHeight, false, opts, 0, "")
   392→			}
   393→		}
   394→
   395→		// Label content.
   396→		drawLabel(pdf, setFont, &contact, sender, tmpl, originX, originY)
   397→
   398→		// QR code.
   399→		if qrPNG != nil {
   400→			drawQR(pdf, job.QRConfig, qrPNG, originX, originY, layout.LabelWidth, layout.LabelHeight, i)
   401→		}
   402→	}
   403→
   404→	var buf bytes.Buffer
   405→	if err := pdf.Output(&buf); err != nil {
   406→		return nil, fmt.Errorf("pdf output: %w", err)
   407→	}
   408→	return buf.Bytes(), nil
   409→}
   410→
   411→// drawQR places a pre-generated QR PNG at the configured position within the label.
   412→func drawQR(pdf *gofpdf.Fpdf, qr *entity.QRConfig, pngBytes []byte, originX, originY, labelW, labelH float64, idx int) {
   413→	// size in mm: qr.Size pixels * 0.264583 mm/px (96 dpi)
   414→	sizeMM := float64(qr.Size) * 0.264583
   415→	if sizeMM < 15 {
   416→		sizeMM = 15 // minimum readable QR size
   417→	}
   418→
   419→	var qrX, qrY float64
   420→	switch qr.Position {
   421→	case "top-left":
   422→		qrX = originX + 1
   423→		qrY = originY + 1
   424→	case "top-right":
   425→		qrX = originX + labelW - sizeMM - 1
   426→		qrY = originY + 1
   427→	case "bottom-left":
   428→		qrX = originX + 1
   429→		qrY = originY + labelH - sizeMM - 1
   430→	default: // "bottom-right"
   431→		qrX = originX + labelW - sizeMM - 1
   432→		qrY = originY + labelH - sizeMM - 1
   433→	}
   434→
   435→	// Register once with a fixed key; gofpdf caches it after first registration.
   436→	const imgKey = "qr_code"
   437→	if idx == 0 {
   438→		reader := bytes.NewReader(pngBytes)
   439→		pdf.RegisterImageOptionsReader(imgKey, gofpdf.ImageOptions{ImageType: "PNG"}, reader)
   440→	}
   441→	pdf.ImageOptions(imgKey, qrX, qrY, sizeMM, sizeMM, false, gofpdf.ImageOptions{ImageType: "PNG"}, 0, "")
   442→}
   443→
   444→// drawLabel renders postal code, recipient and sender onto a single label cell.
   445→func drawLabel(
   446→	pdf *gofpdf.Fpdf,
   447→	setFont func(float64),
   448→	contact *entity.Contact,
   449→	sender *entity.Sender,
   450→	tmpl entity.Template,
   451→	ox, oy float64,
   452→) {
   453→	pdf.SetTextColor(0, 0, 0)
   454→
   455→	// Postal code digits.
   456→	if tmpl.PostalCode != nil && contact.PostalCode != "" {
   457→		setFont(tmpl.PostalCode.FontSize)
   458→		digits := strings.ReplaceAll(contact.PostalCode, "-", "")
   459→		spacing := tmpl.PostalCode.DigitSpacing
   460→		if spacing <= 0 {
   461→			spacing = 4
   462→		}
   463→		cellH := tmpl.PostalCode.FontSize * 0.4
   464→		for i, ch := range digits {
   465→			xPos := ox + tmpl.PostalCode.X + float64(i)*spacing
   466→			pdf.SetXY(xPos, oy+tmpl.PostalCode.Y)
   467→			pdf.CellFormat(spacing, cellH, string(ch), "", 0, "C", false, 0, "")
   468→		}
   469→	}
   470→
   471→	// Recipient name.
   472→	rec := tmpl.Recipient
   473→	honorific := contact.Honorific
   474→	if honorific == "" {
   475→		honorific = "様"
   476→	}
   477→
   478→	var nameLines []string
   479→	if contact.Company != "" {
   480→		nameLines = append(nameLines, contact.Company)
   481→		if contact.Department != "" {
   482→			nameLines = append(nameLines, contact.Department)
   483→		}
   484→	}
   485→	fullName := contact.FamilyName + contact.GivenName + " " + honorific
   486→	nameLines = append(nameLines, fullName)
   487→
   488→	addr := buildAddress(contact)
   489→
   490→	if tmpl.Orientation == "vertical" {
   491→		setFont(rec.NameFont)
   492→		xOff := ox + rec.NameX
   493→		for _, line := range nameLines {
   494→			drawVerticalText(pdf, line, xOff, oy+rec.NameY, rec.NameFont)
   495→			xOff -= rec.NameFont * 0.5 // next column to the left
   496→		}
   497→
   498→		setFont(rec.AddressFont)
   499→		drawVerticalText(pdf, addr, ox+rec.AddressX, oy+rec.AddressY, rec.AddressFont)
   500→	} else {
   501→		setFont(rec.NameFont)
   502→		lineH := rec.NameFont * 0.5
   503→		for i, line := range nameLines {
   504→			pdf.SetXY(ox+rec.NameX, oy+rec.NameY+float64(i)*lineH)
   505→			pdf.CellFormat(0, lineH, line, "", 0, "L", false, 0, "")
   506→		}
   507→
   508→		setFont(rec.AddressFont)
   509→		pdf.SetXY(ox+rec.AddressX, oy+rec.AddressY)
   510→		pdf.CellFormat(0, rec.AddressFont*0.5, addr, "", 0, "L", false, 0, "")
   511→	}
   512→
   513→	// Sender.
   514→	if sender != nil {
   515→		snd := tmpl.Sender
   516→		senderName := sender.FamilyName + sender.GivenName
   517→		if sender.Company != "" {
   518→			senderName = sender.Company + " " + senderName
   519→		}
   520→		senderAddr := buildSenderAddress(sender)
   521→
   522→		if tmpl.Orientation == "vertical" {
   523→			setFont(snd.NameFont)
   524→			drawVerticalText(pdf, senderName, ox+snd.NameX, oy+snd.NameY, snd.NameFont)
   525→			setFont(snd.AddressFont)
   526→			drawVerticalText(pdf, senderAddr, ox+snd.AddressX, oy+snd.AddressY, snd.AddressFont)
   527→		} else {
   528→			setFont(snd.NameFont)
   529→			pdf.SetXY(ox+snd.NameX, oy+snd.NameY)
   530→			pdf.CellFormat(0, snd.NameFont*0.5, senderName, "", 0, "L", false, 0, "")
   531→			setFont(snd.AddressFont)
   532→			pdf.SetXY(ox+snd.AddressX, oy+snd.AddressY)
   533→			pdf.CellFormat(0, snd.AddressFont*0.5, senderAddr, "", 0, "L", false, 0, "")
   534→		}
   535→	}
   536→}
   537→
   538→// drawVerticalText places each rune top-to-bottom in a single column.
   539→func drawVerticalText(pdf *gofpdf.Fpdf, text string, x, y, fontSize float64) {
   540→	charW := fontSize * 0.45
   541→	lineH := fontSize * 0.48
   542→	for i, ch := range text {
   543→		pdf.SetXY(x, y+float64(i)*lineH)
   544→		pdf.CellFormat(charW, lineH, string(ch), "", 0, "C", false, 0, "")
   545→	}
   546→}
   547→
   548→func buildAddress(c *entity.Contact) string {
   549→	var parts []string
   550→	if c.Prefecture != "" {
   551→		parts = append(parts, c.Prefecture)
   552→	}
   553→	if c.City != "" {
   554→		parts = append(parts, c.City)
   555→	}
   556→	if c.Street != "" {
   557→		parts = append(parts, c.Street)
   558→	}
   559→	if c.Building != "" {
   560→		parts = append(parts, c.Building)
   561→	}
   562→	return strings.Join(parts, "")
   563→}
   564→
   565→func buildSenderAddress(s *entity.Sender) string {
   566→	var parts []string
   567→	if s.Prefecture != "" {
   568→		parts = append(parts, s.Prefecture)
   569→	}
   570→	if s.City != "" {
   571→		parts = append(parts, s.City)
   572→	}
   573→	if s.Street != "" {
   574→		parts = append(parts, s.Street)
   575→	}
   576→	if s.Building != "" {
   577→		parts = append(parts, s.Building)
   578→	}
   579→	return strings.Join(parts, "")
   580→}
   581→
   582→func imageType(path string) string {
   583→	lower := strings.ToLower(path)
   584→	switch {
   585→	case strings.HasSuffix(lower, ".png"):
   586→		return "PNG"
   587→	case strings.HasSuffix(lower, ".jpg"), strings.HasSuffix(lower, ".jpeg"):
   588→		return "JPG"
   589→	default:
   590→		return "PNG"
   591→	}
   592→}
