package pdf

import (
	"encoding/binary"
	"fmt"
	"os"
	"testing"
)

func TestDebugCmap(t *testing.T) {
	ttcPath := "/System/Library/Fonts/Supplemental/Songti.ttc"
	data, err := os.ReadFile(ttcPath)
	if err != nil {
		t.Skipf("Songti.ttc not available: %v", err)
	}

	// Try face 0
	face := extractTTCFace(data, 0)
	if face == nil {
		t.Fatal("face 0 is nil")
	}
	t.Logf("face 0 size: %d bytes", len(face))
	t.Logf("face 0 magic: %q", string(face[:4]))

	numTables := int(binary.BigEndian.Uint16(face[4:6]))
	t.Logf("face 0 numTables: %d", numTables)

	// Find cmap table
	var cmapOff, cmapLen uint32
	for i := 0; i < numTables; i++ {
		b := 12 + i*16
		tag := string(face[b : b+4])
		off := binary.BigEndian.Uint32(face[b+8 : b+12])
		length := binary.BigEndian.Uint32(face[b+12 : b+16])
		t.Logf("  table %d: tag=%q off=%d len=%d", i, tag, off, length)
		if tag == "cmap" {
			cmapOff = off
			cmapLen = length
